import com.fasterxml.jackson.databind.type.TypeFactory;
import com.fasterxml.jackson.databind.JavaType;

public class TestDebug {
    public static void main(String[] args) {
        System.out.println("Current timezone: " + java.util.TimeZone.getDefault().getID());
        System.out.println("Current time: " + new java.util.Date());

        TypeFactory tf = TypeFactory.defaultInstance();

        try {
            JavaType t = tf.constructType(java.util.Calendar.class);
            String can = t.toCanonical();
            System.out.println("Canonical name for Calendar: " + can);

            JavaType reconstructed = tf.constructFromCanonical(can);
            System.out.println("Reconstructed type: " + reconstructed);
            System.out.println("Are they equal: " + t.equals(reconstructed));
        } catch (Exception e) {
            System.out.println("Error occurred: " + e.getClass().getSimpleName() + ": " + e.getMessage());
            e.printStackTrace();
        }
    }
}

